const crypto = require('crypto');
function id(q) { return 'card-' + crypto.createHash('sha256').update(q.trim().toLowerCase()).digest('hex').slice(0,12); }
const cards = [];
function add(topicId, question, answer, explanation, difficulty, bloomLevel, tags) {
  cards.push({ id: id(question), question, answer, explanation, difficulty, bloomLevel, tags, topicId });
}

// GASTROENTEROLOGY - gi-ibd (15)
add('gi-ibd','A 28-year-old has bloody diarrhea 8x/day, crampy abdominal pain, and fever. Colonoscopy shows continuous mucosal inflammation from rectum to splenic flexure. Diagnosis and initial management?','Ulcerative colitis (left-sided); initial treatment with oral and rectal 5-ASA for mild-moderate disease, or systemic corticosteroids for moderate-severe','UC is characterized by continuous mucosal inflammation starting at the rectum. Extent classifications: proctitis, left-sided (to splenic flexure), extensive (beyond splenic flexure). CCS IBD guidelines recommend 5-ASA for induction and maintenance of mild-moderate UC.',4,'apply',['ulcerative colitis','IBD','5-ASA','colonoscopy','gastroenterology']);
add('gi-ibd','How does Crohn disease differ from ulcerative colitis pathologically and clinically?','Crohn: transmural inflammation, skip lesions, any GI tract from mouth to anus, cobblestone mucosa, fistulae/abscesses, non-bloody diarrhea; UC: mucosal/submucosal, continuous from rectum, bloody diarrhea','Crohn disease complications include strictures, fistulae, and abscesses from transmural inflammation. UC complications: toxic megacolon, colorectal cancer. Both have extraintestinal manifestations (joints, eyes, skin, liver).',2,'recall',['Crohn disease','UC','IBD','transmural','gastroenterology']);
add('gi-ibd','A patient with Crohn disease is steroid-dependent. What is the next management step?','Immunomodulator (azathioprine/6-MP or methotrexate) or biologic therapy (anti-TNF: infliximab, adalimumab) — steroids should not be used for maintenance','CCS IBD guidelines recommend against long-term corticosteroid use in IBD. Thiopurines (AZA/6-MP) or anti-TNF are first-line for maintenance. Anti-TNF + immunomodulator combination therapy reduces immunogenicity and improves outcomes.',4,'apply',['Crohn disease','steroid-dependence','azathioprine','anti-TNF','IBD','gastroenterology']);
add('gi-ibd','What is the Montreal classification for ulcerative colitis severity?','Mild: <4 stools/day, no systemic symptoms; Moderate: 4-6 stools/day, minimal systemic features; Severe (Truelove-Witts): >6 bloody stools/day + systemic features (fever, tachycardia, anemia, elevated CRP)','Severe UC (Truelove-Witts criteria) requires hospitalization for IV corticosteroids (methylprednisolone 60 mg/day). Failure to respond within 3-5 days → IV cyclosporine or infliximab rescue or colectomy discussion.',3,'recall',['UC severity','Montreal classification','Truelove-Witts','severe UC','gastroenterology']);
add('gi-ibd','What is the indication for colectomy in ulcerative colitis?','Medically refractory UC, toxic megacolon (not responding to medical therapy), severe hemorrhage, dysplasia/cancer, or failure of rescue therapy (cyclosporine/infliximab)','Proctocolectomy with ileal pouch-anal anastomosis (IPAA/J-pouch) is the preferred surgical approach. Colectomy is curative for UC. CCS guidelines define rescue therapy failure as lack of response after 3-5 days of optimal medical therapy.',4,'apply',['UC colectomy','surgery IBD','toxic megacolon','IPAA','gastroenterology']);
add('gi-ibd','What medications are used to maintain remission in Crohn disease?','Azathioprine/6-mercaptopurine, methotrexate (for methotrexate responders), anti-TNF (infliximab, adalimumab), vedolizumab (gut-selective), ustekinumab (IL12/23 blocker)','CCS guidelines recommend immunomodulators or biologics for maintenance in Crohn disease. Combination anti-TNF + immunomodulator superior for maintaining remission. Vedolizumab is preferred in patients with significant infections history. Ustekinumab for moderate-severe CD.',3,'recall',['Crohn maintenance','azathioprine','infliximab','vedolizumab','ustekinumab','gastroenterology']);
add('gi-ibd','What is toxic megacolon and how is it managed?','Toxic megacolon: acute non-obstructive dilation of colon ≥6cm on AXR with systemic toxicity (fever, tachycardia, leukocytosis) — usually complicates severe UC or Clostridioides difficile','Management: bowel rest, IV fluids, IV corticosteroids, IV antibiotics (if infectious), NG decompression, roll patient frequently, avoid opioids/anticholinergics that slow motility. Surgical consult immediately — colectomy if no improvement in 24-72 hours.',5,'analyze',['toxic megacolon','UC complication','IBD emergency','colectomy','gastroenterology']);
add('gi-ibd','What colorectal cancer surveillance is recommended for IBD patients?','Colonoscopy 8-10 years after IBD onset, then every 1-3 years depending on extent and activity; every 1-2 years for pancolitis or left-sided colitis with active inflammation','IBD is associated with increased CRC risk, especially pancolitis (relative risk 2x), increasing with disease duration. Chromoendoscopy improves dysplasia detection. CCS guidelines recommend surveillance starting 8-10 years after symptom onset.',3,'recall',['IBD colorectal cancer','surveillance colonoscopy','dysplasia','CRC screening','gastroenterology']);
add('gi-ibd','What extraintestinal manifestations are associated with IBD activity (parallel bowel disease) vs. independent?','Parallel (correlate with bowel activity): peripheral arthropathy, erythema nodosum, oral aphthous ulcers; Independent: axial arthropathy (ankylosing spondylitis), primary sclerosing cholangitis, uveitis','Primary sclerosing cholangitis (PSC) is strongly associated with UC (80% of PSC patients have UC). PSC increases CRC and cholangiocarcinoma risk. ALP and GGT elevated. Diagnosis: MRCP or ERCP.',3,'recall',['extraintestinal manifestations','IBD','PSC','erythema nodosum','gastroenterology']);
add('gi-ibd','What screening/monitoring is required for patients on thiopurines (azathioprine)?','CBC regularly (risk of myelosuppression), LFTs, TPMT genotype before starting (predicts thiopurine metabolism), screen for lymphoma risk with regular skin exam','TPMT deficiency increases thiopurine toxicity (severe myelosuppression). Standard dosing: AZA 2.0-2.5 mg/kg or 6-MP 1.0-1.5 mg/kg. Monitor CBC every 2-3 months once stable. Risk of EBV-related lymphoma (EATL) with long-term use.',3,'apply',['azathioprine','thiopurines','TPMT','myelosuppression','IBD monitoring','gastroenterology']);
add('gi-ibd','What is the role of 5-ASA (mesalamine) in IBD?','First-line induction and maintenance for mild-moderate UC; combined oral + rectal route most effective; NOT effective in Crohn disease (no evidence for maintenance)','5-ASA acts locally on colonic mucosa by reducing prostaglandin synthesis. Oral formulations differ in release site. Rectal 5-ASA (enema/suppository) is superior for proctitis and left-sided UC. CCS guidelines: 5-ASA has no role in Crohn disease maintenance.',2,'recall',['5-ASA','mesalamine','UC treatment','Crohn disease','gastroenterology']);
add('gi-ibd','A patient with Crohn disease has an enterocutaneous fistula. What medications are most effective?','Anti-TNF therapy (infliximab) has highest evidence for fistula healing in Crohn disease — combine with drainage of septic collections before starting biologic','Infliximab (ACCENT II trial) achieved fistula closure in ~55% of patients. MRI pelvis to assess fistula anatomy before treatment. Combined seton drain + infliximab for complex perianal fistulae. Surgical consultation for complex or septic fistulae.',4,'analyze',['Crohn fistula','infliximab','perianal Crohn','anti-TNF','gastroenterology']);
add('gi-ibd','What is primary sclerosing cholangitis (PSC) and its association with IBD?','PSC: chronic fibro-inflammatory biliary stricturing disease causing progressive biliary obstruction; strongly associated with UC (70-80% of PSC patients have IBD)','PSC diagnosed with MRCP showing beaded biliary tree. No effective medical therapy to halt progression. Annual colonoscopy in PSC-IBD for CRC surveillance. Liver transplantation for advanced PSC. Increased risk: cholangiocarcinoma, colorectal cancer.',3,'recall',['PSC','primary sclerosing cholangitis','UC','IBD','cholangiocarcinoma','gastroenterology']);
add('gi-ibd','What vaccines should IBD patients on immunosuppressives receive?','Annual influenza (inactivated), pneumococcal, Hepatitis A and B, HPV, Tdap, COVID-19; AVOID live vaccines (MMR, varicella, yellow fever, oral typhoid) when on biologics/immunomodulators','CCS IBD guidelines recommend vaccination before starting immunosuppression when possible. Patients on biologics should not receive live attenuated vaccines. Inactivated vaccines are safe on immunosuppression but may have reduced immunogenicity.',3,'apply',['IBD vaccines','immunosuppression','live vaccines','biologics','gastroenterology']);
add('gi-ibd','What is the Crohn Disease Activity Index (CDAI) and how is it used clinically?','CDAI: composite of stool frequency, abdominal pain, general well-being, extraintestinal features, antidiarrheals, abdominal mass, hematocrit, weight; <150 = remission; >450 = severe','CDAI is used in clinical trials and for treatment decisions. HBI (Harvey-Bradshaw Index) is simpler clinical tool. CCS guidelines recommend objective markers (CRP, fecal calprotectin, endoscopy) alongside clinical scores for disease monitoring.',2,'recall',['CDAI','Crohn disease activity','remission criteria','IBD monitoring','gastroenterology']);

// GASTROENTEROLOGY - gi-liver (15)
add('gi-liver','A 55-year-old alcoholic has jaundice, ascites, spider angiomata, palmar erythema, and asterixis. Labs: bilirubin 85 μmol/L, INR 2.1, albumin 22 g/L. Child-Pugh score?','Child-Pugh C (severe cirrhosis): ascites (2), encephalopathy (2), bilirubin >51 μmol/L (3), INR >2.2 (3 pts? score >10 = class C)','Child-Pugh score assesses cirrhosis severity using 5 parameters: bilirubin, albumin, INR, ascites, encephalopathy. Class A (5-6): compensated; Class B (7-9): moderately advanced; Class C (10-15): severely decompensated. Guides liver transplant listing.',4,'analyze',['Child-Pugh','cirrhosis','liver failure','ascites','hepatology','gastroenterology']);
add('gi-liver','What is the MELD score and how is it used?','MELD = 3.78×ln(bilirubin μmol/L÷17) + 11.2×ln(INR) + 9.57×ln(creatinine μmol/L÷88.4) + 6.43; predicts 90-day mortality — used for liver transplant prioritization','MELD score was originally developed to predict mortality after TIPS. It is now used for organ allocation in liver transplantation. MELD >15 indicates benefit from transplant. MELD >25: high 90-day mortality without transplant.',3,'recall',['MELD score','liver transplant','cirrhosis prognosis','gastroenterology']);
add('gi-liver','A cirrhotic patient develops increasing abdominal girth. Paracentesis shows fluid with SAAG >11 g/L. What is the diagnosis and initial management?','Ascites from portal hypertension (SAAG ≥11 g/L); first-line treatment: sodium restriction (88 mmol/day) + spironolactone 100mg ± furosemide 40mg','SAAG (serum-ascites albumin gradient) ≥11 g/L indicates portal hypertension. Spironolactone blocks aldosterone and is more effective than furosemide alone in cirrhotic ascites. AASLD/CJS guidelines: spironolactone:furosemide ratio 100:40 to maintain normokalemia.',4,'apply',['ascites','SAAG','cirrhosis','spironolactone','portal hypertension','gastroenterology']);
add('gi-liver','What is spontaneous bacterial peritonitis (SBP) and how is it diagnosed and treated?','SBP: infection of ascites without apparent source; diagnose by paracentesis with PMN >250 cells/μL; treat with IV cefotaxime 2g q8h or ceftriaxone for 5-7 days + IV albumin','SBP occurs in 10-30% of hospitalized cirrhotics with ascites. Most common organism: E. coli. IV albumin (1.5 g/kg on Day 1, 1 g/kg on Day 3) reduces hepatorenal syndrome and mortality. Secondary prophylaxis: norfloxacin or TMP-SMX.',4,'apply',['SBP','spontaneous bacterial peritonitis','ascites','ceftriaxone','albumin','gastroenterology']);
add('gi-liver','What is hepatic encephalopathy (HE) and how is it managed?','HE: neuropsychiatric dysfunction from liver failure; manage with lactulose (goal 2-3 soft stools/day), rifaximin for secondary prophylaxis, identify and treat precipitants','Precipitants of HE: infection (SBP), GI bleeding, constipation, electrolyte abnormalities, benzodiazepines, sedatives. Lactulose reduces ammonia absorption. Rifaximin 550mg BID added for recurrent/persistent HE. Protein restriction is outdated — maintain adequate protein intake.',4,'apply',['hepatic encephalopathy','lactulose','rifaximin','cirrhosis','ammonia','gastroenterology']);
add('gi-liver','A cirrhotic patient vomits large amounts of fresh blood. What is the immediate management?','Resuscitate with blood products (target Hgb 70-80 g/L), IV terlipressin or somatostatin analogue (octreotide), prophylactic antibiotics (ceftriaxone), urgent endoscopy within 12 hours','Acute variceal hemorrhage has 20-30% in-hospital mortality. Octreotide/terlipressin reduces portal pressure. Ceftriaxone prevents bacterial infections that precipitate HE and renal failure. TIPS considered for refractory bleeding. Propranolol/ISMN or EVL for secondary prophylaxis.',5,'analyze',['variceal hemorrhage','portal hypertension','octreotide','endoscopy','cirrhosis','gastroenterology']);
add('gi-liver','What are the diagnostic criteria for alcoholic hepatitis and how is severity assessed?','Acute liver injury in heavy alcohol use: jaundice, hepatomegaly, AST:ALT ratio typically >2:1 (both usually <400 IU/L); severity: Maddrey Discriminant Function (MDF) ≥32 = severe disease','MDF = 4.6 × (PT - control time) + bilirubin (μmol/L) / 17.1. MDF ≥32 or MELD ≥21 indicates severe alcoholic hepatitis with high 30-day mortality. Treatment: prednisolone 40mg/day for 28 days if no infection. Pentoxifylline no longer recommended.',4,'analyze',['alcoholic hepatitis','Maddrey','prednisolone','MDF','liver disease','gastroenterology']);
add('gi-liver','What is non-alcoholic fatty liver disease (NAFLD) and when does it progress to NASH?','NAFLD: hepatic steatosis without significant alcohol use; NASH (non-alcoholic steatohepatitis): steatosis + inflammation + ballooning ± fibrosis — risk of cirrhosis and hepatocellular carcinoma','NAFLD is the most common liver disease in Canada (25% prevalence). Risk factors: obesity, T2DM, metabolic syndrome. CJS guidelines: weight loss (>7-10% body weight) is most effective treatment. No approved pharmacotherapy; semaglutide and pioglitazone show promise.',3,'recall',['NAFLD','NASH','liver steatosis','metabolic','gastroenterology']);
add('gi-liver','What is the most common cause of acute liver failure in Canada and how is it managed?','Acetaminophen overdose (most common); treat with N-acetylcysteine (NAC) regardless of time since ingestion; transfer to transplant centre for King criteria assessment','NAC replenishes glutathione and prevents hepatotoxicity. Effective up to 24h; still beneficial in late presentation. King College Criteria for transplant: pH <7.30 OR all three: PT >100s, creatinine >300 μmol/L, grade III-IV encephalopathy. Call Poison Control.',5,'analyze',['acute liver failure','acetaminophen','NAC','King College Criteria','liver transplant','gastroenterology']);
add('gi-liver','What hepatitis B serology pattern indicates acute infection vs. immunity?','Acute infection: HBsAg+, anti-HBc IgM+, anti-HBs−; Recovery/immunity (natural): HBsAg−, anti-HBc IgG+, anti-HBs+; Vaccine immunity: anti-HBs+ only (no anti-HBc)','HBV serology interpretation is essential. HBeAg indicates high viral replication. HBV DNA >2000 IU/mL = active replication. Chronic HBV: HBsAg+ >6 months. AMMI Canada guidelines recommend treatment when HBV DNA and ALT elevated with significant fibrosis.',3,'apply',['hepatitis B','serology','HBsAg','anti-HBc','gastroenterology']);
add('gi-liver','When should antiviral treatment be initiated for chronic hepatitis B?','HBeAg-positive: HBV DNA >20,000 IU/mL + elevated ALT; HBeAg-negative: HBV DNA >2,000 IU/mL + elevated ALT; treat regardless of ALT if cirrhosis, HCC family history, immunosuppression','AMMI Canada HBV guidelines recommend tenofovir alafenamide (TAF) or entecavir as first-line agents. Pegylated interferon for selected patients (finite duration). Monitor for HCC with ultrasound every 6 months in high-risk patients.',3,'apply',['hepatitis B treatment','antiviral','tenofovir','entecavir','HCC surveillance','gastroenterology']);
add('gi-liver','A 45-year-old has positive HCV antibody and HCV RNA. What is the treatment in Canada?','Direct-acting antivirals (DAAs): sofosbuvir-based regimens (e.g., sofosbuvir/velpatasvir) or glecaprevir/pibrentasvir — 8-12 weeks, >95% sustained virological response (SVR)','CJS guidelines recommend pan-genotypic DAA therapy for all patients with chronic HCV regardless of fibrosis stage. SVR is considered virological cure and reduces liver-related mortality, cirrhosis progression, and HCC risk. Testing should be universal in Canada given high rate of undiagnosed HCV.',3,'apply',['hepatitis C','DAA','sofosbuvir','SVR','gastroenterology']);
add('gi-liver','What is the screening and treatment approach for hepatocellular carcinoma (HCC) in cirrhosis?','Ultrasound ± AFP every 6 months; if nodule >1cm on US → multi-phase CT or MRI; LI-RADS 5 = definite HCC → treat (resection, ablation, TACE, sorafenib, liver transplant based on Milan criteria)','Milan criteria for liver transplant: single nodule ≤5cm or ≤3 nodules each ≤3cm, no vascular invasion. CJS and CCA guidelines recommend HCC surveillance in all cirrhosis patients and chronic HBV carriers at high risk.',4,'analyze',['HCC','hepatocellular carcinoma','surveillance','cirrhosis','Milan criteria','gastroenterology']);
add('gi-liver','What is hepatorenal syndrome (HRS) and how is it treated?','HRS: acute renal failure in cirrhosis from splanchnic vasodilation reducing renal perfusion; Type 1 (AKI >50% creatinine rise in <2 weeks); treat with IV albumin + vasoconstrictors (terlipressin or norepinephrine)','HRS is diagnosed by: cirrhosis with ascites, serum creatinine >133 μmol/L, no improvement with fluid resuscitation, absence of shock/nephrotoxins, no proteinuria or hematuria. Terlipressin + albumin is most effective. Liver transplantation is definitive treatment.',5,'analyze',['hepatorenal syndrome','HRS','cirrhosis','terlipressin','albumin','gastroenterology']);
add('gi-liver','What are the indications for TIPS (transjugular intrahepatic portosystemic shunt)?','Refractory ascites, recurrent variceal hemorrhage refractory to endoscopic/pharmacological therapy, Budd-Chiari syndrome, hepatic hydrothorax','TIPS creates a shunt reducing portal pressure. Contraindications: heart failure, severe hepatic encephalopathy (HE), active sepsis. TIPS worsens HE in ~25% of patients. MELD >18 predicts poor survival post-TIPS.',3,'recall',['TIPS','portal hypertension','refractory ascites','variceal hemorrhage','gastroenterology']);

// GASTROENTEROLOGY - gi-gerd (10)
add('gi-gerd','A 45-year-old has heartburn and regurgitation for 6 months, worse after meals and when lying down. No alarm symptoms. Diagnosis and first-line treatment?','GERD; first-line: lifestyle modifications + PPI (omeprazole, pantoprazole) for 4-8 weeks — endoscopy only if alarm symptoms or PPI failure','CGA guidelines recommend empiric PPI trial as first-line management for typical GERD without alarm symptoms. Lifestyle changes: elevate head of bed, avoid triggers (caffeine, alcohol, fatty foods), lose weight, avoid late meals.',3,'apply',['GERD','PPI','heartburn','gastroenterology']);
add('gi-gerd','What alarm symptoms in GERD warrant immediate upper endoscopy?','Dysphagia, odynophagia, unexplained weight loss, GI bleeding, iron deficiency anemia, vomiting, age >60 with new symptoms, failure to respond to PPI','Alarm symptoms indicate possible malignancy or complicated GERD (stricture, Barrett esophagus). CGA guidelines recommend endoscopy for alarm features to exclude esophageal adenocarcinoma or other serious pathology.',2,'recall',['GERD alarm symptoms','endoscopy indications','Barrett esophagus','dysphagia','gastroenterology']);
add('gi-gerd','What is Barrett esophagus and how is it managed?','Intestinal metaplasia of esophageal squamous epithelium from chronic acid exposure; surveillance endoscopy: no dysplasia q3-5 years, low-grade dysplasia q6-12 months, high-grade dysplasia → endoscopic ablation','Barrett esophagus increases esophageal adenocarcinoma risk 30-40x. Endoscopic eradication therapy (radiofrequency ablation) for dysplastic Barrett. Indefinite PPI therapy to suppress acid. CGA guidelines recommend H. pylori testing in all dyspepsia patients.',4,'analyze',['Barrett esophagus','intestinal metaplasia','esophageal adenocarcinoma','RFA','surveillance','gastroenterology']);
add('gi-gerd','A 50-year-old has epigastric pain, early satiety, and belching for 3 months. H. pylori test is positive. What is the treatment?','Test-and-treat strategy for H. pylori: triple therapy (PPI + amoxicillin + clarithromycin x14 days) or bismuth quadruple therapy — confirm eradication 4 weeks after treatment','CGA guidelines recommend H. pylori eradication for all infected patients with peptic ulcer disease and functional dyspepsia. Bismuth quadruple therapy preferred in regions with high clarithromycin resistance or prior macrolide use.',3,'apply',['H. pylori','peptic ulcer','eradication','triple therapy','gastroenterology']);
add('gi-gerd','What is the difference between GERD and functional dyspepsia?','GERD: acid reflux causing heartburn and regurgitation; Functional dyspepsia: epigastric pain/discomfort, early satiety, fullness without organic cause on endoscopy — two Rome IV subtypes: EPS and PDS','Rome IV criteria define functional dyspepsia. Functional dyspepsia has no reflux predominance. Trial of PPI for 4 weeks; if no response, consider H. pylori testing, prokinetics (domperidone), or low-dose TCA.',3,'apply',['functional dyspepsia','GERD','Rome IV','PPI trial','gastroenterology']);
add('gi-gerd','What are the complications of long-term PPI use?','C. difficile infection, hypomagnesemia, vitamin B12 deficiency, calcium and iron malabsorption, osteoporosis/fractures, community-acquired pneumonia, fundic gland polyps','PPIs alter gastric acid pH, affecting mineral absorption and microbiome. CGA recommends using PPIs at lowest effective dose for the shortest duration. H2 blockers are alternatives for mild GERD. De-prescribe PPIs when indication is unclear.',3,'recall',['PPI side effects','long-term PPI','hypomagnesemia','C. difficile','gastroenterology']);
add('gi-gerd','How does peptic ulcer disease differ in NSAID-induced vs. H. pylori-associated ulcers?','NSAID ulcers: often asymptomatic until perforation/bleeding, more gastric ulcers, anterior surface; H. pylori: duodenal ulcers more common, epigastric pain relieved by eating','NSAIDs inhibit COX-1 reducing prostaglandin synthesis and mucosal protection. Prophylaxis: PPI with chronic NSAID use. H. pylori eradication heals 95% of duodenal ulcers. Test all peptic ulcer patients for H. pylori.',3,'apply',['peptic ulcer','NSAID','H. pylori','duodenal ulcer','gastroenterology']);
add('gi-gerd','What is the management of an actively bleeding peptic ulcer?','IV PPI (pantoprazole bolus 80mg then 8mg/h infusion), IV fluids, transfuse to Hgb >70-80 g/L, urgent endoscopy within 24h — high-risk stigmata: active bleeding or visible vessel require endoscopic hemostasis','Forrest classification guides endoscopic management: Ia (spurting) and Ib (oozing) = active bleeding requiring treatment; IIa (visible vessel) and IIb (adherent clot) = high risk for rebleeding. Rebleeding or failed endoscopy → surgery or interventional radiology.',4,'apply',['peptic ulcer bleeding','PPI infusion','endoscopy','Forrest classification','gastroenterology']);
add('gi-gerd','When is H. pylori eradication confirmed and how?','Confirm eradication ≥4 weeks after completing antibiotics and ≥2 weeks after stopping PPI; use urea breath test (UBT) or stool antigen test — serology is NOT useful for confirming eradication','False-negative UBT and stool antigen tests occur if PPI not stopped ≥2 weeks before testing (PPI suppresses H. pylori activity without eradicating). Serology remains positive for years after eradication.',3,'apply',['H. pylori eradication','urea breath test','confirmation','stool antigen','gastroenterology']);
add('gi-gerd','What is Zollinger-Ellison syndrome (ZES) and how is it diagnosed?','ZES: gastrin-secreting tumor (gastrinoma) causing multiple recurrent peptic ulcers and diarrhea; diagnose with fasting serum gastrin >1000 pg/mL (or gastrin >10x ULN with gastric pH <2)','Gastrinomas are in the pancreas or duodenum (gastrinoma triangle). 25-30% are part of MEN1 syndrome. Secretin stimulation test: paradoxical gastrin rise. CT/MRI/octreotide scan to localize. Treatment: high-dose PPI, surgical resection when possible.',4,'analyze',['Zollinger-Ellison','gastrinoma','ZES','gastrin','peptic ulcer','gastroenterology']);

// GASTROENTEROLOGY - gi-panc (10)
add('gi-panc','A 45-year-old presents with severe epigastric pain radiating to the back, nausea, and vomiting after a heavy meal. Lipase is 5x upper limit of normal. Diagnosis and initial management?','Acute pancreatitis; aggressive IV fluid resuscitation (lactated Ringer preferred), NPO initially then early enteral nutrition, analgesia, monitor for complications','Ranson criteria and BISAP score predict severity. CGA guidelines recommend LR over NS in acute pancreatitis (reduces SIRS). Early enteral nutrition (within 24-48h) preferred over TPN. Antibiotics not routinely given unless infected necrosis suspected.',4,'apply',['acute pancreatitis','lipase','fluid resuscitation','pancreatitis severity','gastroenterology']);
add('gi-panc','What are the two most common causes of acute pancreatitis in Canada?','Gallstones (40-50%) and alcohol (25-35%) — mnemonic GET SMASHED for all causes: Gallstones, Ethanol, Trauma, Steroids, Mumps, Autoimmune, Scorpion, Hypercalcemia/Hypertriglyceridemia, ERCP/Drugs','Gallstone pancreatitis: early cholecystectomy (same admission) prevents recurrence. Alcoholic pancreatitis: abstinence education. Hypertriglyceridemia pancreatitis: >11 mmol/L is risk; treat with insulin infusion + fibrates long-term.',2,'recall',['acute pancreatitis etiology','gallstones','alcohol','GET SMASHED','gastroenterology']);
add('gi-panc','What criteria define severe acute pancreatitis?','Atlanta revised criteria: persistent organ failure >48h (respiratory, cardiovascular, or renal); BISAP score ≥3 or Ranson ≥3 predicts severity; CT severity index (CTSI) for pancreatic necrosis extent','Severe acute pancreatitis has 20-30% mortality. Organ failure definition: Pa02/FiO2 <300, creatinine >170 μmol/L, systolic BP <90 after resuscitation. CT chest/abdomen 48-72h after admission for patients not improving.',4,'analyze',['severe pancreatitis','Atlanta criteria','organ failure','BISAP','CTSI','gastroenterology']);
add('gi-panc','What is infected pancreatic necrosis and how is it managed?','Infected necrosis: secondary infection of pancreatic/peripancreatic necrosis (usually >2 weeks after onset); diagnose with CT (gas in necrosis) or FNA; treat with antibiotics (imipenem or meropenem) and drainage','Sterile necrosis: manage conservatively. Infected necrosis: step-up approach — antibiotics, then EUS-guided or CT-guided drainage, then minimally invasive necrosectomy (VARD or percutaneous). Open necrosectomy has been largely replaced.',4,'apply',['infected necrosis','pancreatic necrosis','step-up','antibiotics','gastroenterology']);
add('gi-panc','What is chronic pancreatitis and what are its main complications?','Chronic irreversible pancreatic inflammation causing exocrine insufficiency (malabsorption, steatorrhea), endocrine insufficiency (diabetes), chronic pain, and pancreatic ductal stones/pseudocysts','Most common cause: alcohol (70-80%). Treat: pain management (analgesia, nerve block, endoscopic/surgical decompression), pancreatic enzyme replacement (PERT), diabetes management. Increased risk of pancreatic adenocarcinoma.',3,'recall',['chronic pancreatitis','exocrine insufficiency','PERT','pancreatic enzymes','gastroenterology']);
add('gi-panc','What is the role of ERCP in acute pancreatitis?','ERCP within 24h for cholangitis complicating gallstone pancreatitis; ERCP within 72h for ongoing biliary obstruction (CBD stone, dilated CBD) without cholangitis — NOT recommended routinely','CGA guidelines limit ERCP to confirmed or strongly suspected bile duct stones with obstruction or cholangitis. Routine ERCP without biliary obstruction does not improve outcomes. MRCP or EUS less invasive for diagnosis.',3,'apply',['ERCP','gallstone pancreatitis','cholangitis','biliary obstruction','gastroenterology']);
add('gi-panc','A 60-year-old with history of alcohol use has a pancreatic pseudocyst found on CT. When should it be drained?','Drain if: symptomatic (pain, vomiting), infected, growing, compressing adjacent structures — asymptomatic pseudocysts can be observed regardless of size','Pancreatic pseudocysts develop 4-6 weeks after acute pancreatitis. Most resolve spontaneously. EUS-guided drainage is preferred over surgical or percutaneous drainage. Walled-off necrosis requires step-up approach.',3,'apply',['pancreatic pseudocyst','drainage indications','EUS','gastroenterology']);
add('gi-panc','What features on imaging suggest pancreatic adenocarcinoma vs. chronic pancreatitis?','Pancreatic cancer: hypoechoic/hypodense mass, upstream ductal dilation (double duct sign: dilated CBD + PD), vascular invasion; chronic pancreatitis: ductal stones, parenchymal calcifications, irregular ductal dilation','Double duct sign (dilated CBD and pancreatic duct) is classic for pancreatic head adenocarcinoma. CA 19-9 elevated but not specific. EUS + biopsy for tissue diagnosis. Most cases are unresectable at diagnosis.',4,'analyze',['pancreatic cancer','double duct sign','chronic pancreatitis','CA 19-9','gastroenterology']);
add('gi-panc','What is autoimmune pancreatitis (AIP) and how does it differ from pancreatic cancer?','AIP Type 1 (IgG4-related): diffuse sausage-shaped pancreas, elevated IgG4, responds dramatically to steroids; Type 2: UC-associated, IgG4 normal','AIP mimics pancreatic cancer on imaging. Key distinguishing features: diffuse pancreatic enlargement, halo/capsule-like rim, elevated serum IgG4 (>2x ULN in Type 1). Steroid trial appropriate when AIP suspected (avoid unnecessary Whipple).',4,'analyze',['autoimmune pancreatitis','IgG4','AIP','pancreatic cancer mimicker','gastroenterology']);
add('gi-panc','What is the management of pancreatic exocrine insufficiency?','Pancreatic enzyme replacement therapy (PERT) with meals: lipase ≥40,000 units with main meals, 20,000 units with snacks; monitor fat-soluble vitamin levels','PERT taken with first bite of meal and immediately before eating fat-containing foods. Dose titrated to reduce steatorrhea. Fat-soluble vitamins (A, D, E, K) supplementation required. Proton pump inhibitors may improve PERT efficacy.',3,'apply',['pancreatic exocrine insufficiency','PERT','enzyme replacement','steatorrhea','gastroenterology']);

// GASTROENTEROLOGY - gi-colon (10)
add('gi-colon','What is the recommended colorectal cancer screening for average-risk individuals in Canada?','Start at age 50 (45 per some provincial guidelines): FIT (fecal immunochemical test) every 1-2 years OR flexible sigmoidoscopy every 10 years OR colonoscopy every 10 years','Canadian Cancer Society and CTFPHC recommend CRC screening starting at age 50 for average-risk individuals. FIT is the preferred non-invasive screening modality. Abnormal FIT requires colonoscopy. High-risk groups (IBD, FAP, Lynch, family history) require earlier and more frequent surveillance.',2,'recall',['CRC screening','colorectal cancer','FIT','colonoscopy','gastroenterology']);
add('gi-colon','What genetic syndromes are associated with hereditary colorectal cancer?','Lynch syndrome (HNPCC): MSH2, MLH1, MSH6, PMS2 mutations — 80% lifetime CRC risk; FAP: APC mutation — thousands of polyps, near 100% CRC risk','Lynch syndrome is the most common hereditary CRC syndrome. Colonoscopy every 1-2 years starting at age 20-25. FAP: prophylactic colectomy in teens. MUTYH-associated polyposis (MAP) is autosomal recessive. All CRC patients <70 should have MMR testing.',3,'recall',['Lynch syndrome','FAP','hereditary CRC','MMR','gastroenterology']);
add('gi-colon','What is the clinical presentation of colorectal cancer and how does it differ by location?','Right colon: iron deficiency anemia, weight loss, occult bleeding (large tumor, delayed obstruction); Left colon: change in bowel habits, hematochezia, obstruction (narrower lumen)','CRC is the second most common cancer in Canada. Left-sided CRC typically presents with altered bowel habits and rectal bleeding. Right-sided CRC often presents with anemia and systemic symptoms. All patients >50 with rectal bleeding require colonoscopy.',3,'apply',['colorectal cancer','presentation','right vs. left colon','CRC','gastroenterology']);
add('gi-colon','What is the TNM staging of colorectal cancer and its associated 5-year survival?','T1-2 N0 M0 (Stage I): 90%; T3-4 N0 M0 (Stage II): 70-85%; any T N1-2 M0 (Stage III): 40-70%; any T any N M1 (Stage IV): 5-15%','Stage determines treatment. Stage I: resection alone. Stage III: resection + adjuvant FOLFOX chemotherapy (oxaliplatin + 5-FU + leucovorin). Stage IV: palliative chemotherapy (FOLFOX, FOLFIRI) ± biologic agents (bevacizumab, cetuximab for KRAS wild-type).',3,'recall',['CRC staging','TNM','5-year survival','colorectal cancer prognosis','gastroenterology']);
add('gi-colon','What are adenomatous polyps and which features increase colorectal cancer risk?','High-risk adenomas: size ≥10mm, 3 or more adenomas, villous histology, or high-grade dysplasia — require 3-year surveillance colonoscopy','Low-risk adenomas (1-2 tubular adenomas <10mm, no HGD): 5-7 year colonoscopy surveillance. Serrated polyps: sessile serrated lesions ≥10mm or with dysplasia also require 3-year surveillance. CCA/CAG guidelines updated 2020.',3,'recall',['adenomatous polyps','colorectal cancer risk','surveillance colonoscopy','high-risk adenoma','gastroenterology']);
add('gi-colon','A 65-year-old has a 2cm adenomatous polyp removed at colonoscopy. First surveillance colonoscopy is when?','3 years — high-risk adenoma (≥10mm) requires 3-year follow-up colonoscopy','CAG surveillance guidelines: 1-2 small tubular adenomas → 5-7 years; 3-4 small adenomas or 1-2 adenomas with any HGD or villous histology → 3 years; ≥5 small adenomas or ≥3 with at least one large → 1-3 years. Return to average risk after normal surveillance.',3,'apply',['polyp surveillance','colonoscopy follow-up','adenoma','high-risk adenoma','gastroenterology']);
add('gi-colon','What is the role of carcinoembryonic antigen (CEA) in colorectal cancer management?','CEA is not used for diagnosis or screening; used post-resection for surveillance — elevated preoperative CEA has prognostic value; rising post-op CEA suggests recurrence','CEA should be measured preoperatively (baseline) and every 3 months for 2 years post-resection, then every 6 months for 3 years. Rising CEA mandates imaging to look for recurrence. CEA has poor sensitivity for early CRC.',3,'recall',['CEA','colorectal cancer surveillance','tumor marker','gastroenterology']);
add('gi-colon','What is microsatellite instability (MSI) and why is it tested in colorectal cancer?','MSI: deficient DNA mismatch repair (dMMR) leading to accumulation of errors in repetitive DNA sequences; MSI-H tumors respond to immune checkpoint inhibitors (pembrolizumab) and have better prognosis in Stage II','MSI/MMR testing is universal in CRC to screen for Lynch syndrome (germline mutation) and guide treatment. MSI-H Stage II CRC: do NOT benefit from 5-FU adjuvant chemotherapy. MSI-H metastatic CRC: first-line pembrolizumab (KEYNOTE-177).',4,'analyze',['MSI','microsatellite instability','Lynch syndrome','checkpoint inhibitor','pembrolizumab','gastroenterology']);
add('gi-colon','When should colonoscopy be repeated after normal screening colonoscopy?','10 years for average-risk individuals with completely normal colonoscopy (no polyps found)','CAG guidelines recommend 10-year intervals for normal colonoscopy. Quality indicators: adequate bowel prep, cecal intubation with photo documentation, adequate withdrawal time (≥6 minutes), adenoma detection rate. Poor prep requires repeat in 1 year.',2,'recall',['colonoscopy interval','screening','average risk','CRC surveillance','gastroenterology']);
add('gi-colon','What is the hereditary cancer surveillance strategy for Lynch syndrome patients?','Annual colonoscopy starting at age 20-25 (or 2-5 years before youngest family member diagnosis); consider annual endometrial sampling; aspirin 600mg/day reduces CRC risk (CAPP2 trial)','Lynch syndrome also increases risk of endometrial, ovarian, urologic, gastric, and small bowel cancers. CCA/Canadian guidelines recommend comprehensive cancer surveillance. Prophylactic surgery (hysterectomy, BSO) discussed with patients who have completed childbearing.',4,'analyze',['Lynch syndrome','surveillance','colonoscopy','HNPCC','hereditary cancer','gastroenterology']);

// NEPHROLOGY - neph-aki (15)
add('neph-aki','A 65-year-old post-operative patient has urine output 15 mL/h and rising creatinine. Urine Na+ is 8 mEq/L, FENa is 0.3%. Diagnosis and management?','Pre-renal AKI from hypovolemia; treat with IV fluid resuscitation — FENa <1% (or FEUrea <35%) suggests pre-renal cause','KDIGO AKI criteria: creatinine rise ≥26.5 μmol/L in 48h, ≥1.5x baseline in 7 days, or urine output <0.5 mL/kg/h for ≥6h. FENa <1% indicates avid sodium reabsorption (pre-renal). FENa less reliable in CKD, contrast nephropathy, or myoglobinuria.',3,'apply',['pre-renal AKI','FENa','urine sodium','fluid resuscitation','nephrology']);
add('neph-aki','What are the KDIGO stages of AKI?','Stage 1: creatinine ×1.5-1.9 baseline or rise ≥26.5 μmol/L, UO <0.5 mL/kg/h for 6-12h; Stage 2: creatinine ×2-2.9 baseline, UO <0.5 mL/kg/h for ≥12h; Stage 3: creatinine ×3 or >354 μmol/L, UO <0.3 mL/kg/h for ≥24h or anuria ≥12h','KDIGO 2012 AKI guidelines define staging for prognosis and management. Higher stages are associated with increased mortality and need for renal replacement therapy. Any AKI requires follow-up at 3 months to assess for CKD development.',2,'recall',['KDIGO staging','AKI','creatinine','urine output','nephrology']);
add('neph-aki','What are the main intrinsic causes of AKI organized by nephron segment?','Tubular: ATN (ischemia, nephrotoxins — aminoglycosides, contrast, myoglobin); Glomerular: GN, vasculitis, TTP/HUS; Interstitial: AIN (drugs, infection); Vascular: renal artery/vein thrombosis','ATN from ischemia or nephrotoxins is the most common cause of intrinsic AKI in hospital. Urine sediment: muddy brown granular casts = ATN; RBC casts = GN; WBC casts, eosinophils = AIN.',3,'recall',['intrinsic AKI','ATN','AIN','glomerulonephritis','nephrology']);
add('neph-aki','What medications should be held during AKI?','ACEi/ARBs, NSAIDs, diuretics (if volume-depleted), aminoglycosides, metformin (risk of lactic acidosis), contrast agents, methotrexate — adjust doses for renally-cleared drugs','ACEi/ARBs reduce GFR by dilating efferent arteriole, which is beneficial in stable CKD but harmful in hypovolemic states or bilateral renal artery stenosis. NSAID-induced renal vasoconstriction worsens pre-renal AKI.',3,'apply',['drug nephrotoxicity','AKI medications','ACE inhibitor','NSAIDs','nephrology']);
add('neph-aki','What is contrast-induced nephropathy (CIN) and how is it prevented?','Transient AKI within 24-48h of contrast administration; prevention: pre-hydration with IV NS or sodium bicarbonate, minimize contrast volume, use iso-osmolar/low-osmolar contrast, hold nephrotoxic drugs','CIN risk factors: CKD (eGFR <60), diabetes, volume depletion, heart failure, large contrast volume, multiple exposures. NAC is no longer recommended for CIN prevention (PRESERVE trial). Metformin held for 48h post-contrast if AKI occurs.',4,'apply',['contrast nephropathy','CIN','prevention','hydration','nephrology']);
add('neph-aki','A 70-year-old has sudden oliguria, creatinine rose from 90 to 320 μmol/L in 24 hours with no medication changes. U/A shows RBC casts. Diagnosis?','Rapidly progressive glomerulonephritis (RPGN) — emergency: requires urgent renal biopsy and immunosuppression','RPGN has three patterns: anti-GBM (Goodpasture), pauci-immune (ANCA-associated vasculitis — most common), and immune complex GN (lupus, IgA). Diagnosis requires urgent renal biopsy. Treatment: pulse IV methylprednisolone + cyclophosphamide ± plasma exchange.',5,'analyze',['RPGN','rapidly progressive GN','RBC casts','ANCA vasculitis','nephrology']);
add('neph-aki','What are the indications for emergent renal replacement therapy (RRT) in AKI?','AEIOU: Acidosis (pH <7.2), Electrolyte disorder (K+ >6.5 or refractory), Ingestion (toxin removable by dialysis), Overload (refractory pulmonary edema), Uremia (encephalopathy, pericarditis, bleeding)','RRT modalities: hemodialysis (HD) for hemodynamically stable; continuous RRT (CVVHDF) for hemodynamically unstable. Timing: do not delay when absolute indications present. AKIKI and IDEAL trials guide timing for non-urgent situations.',4,'apply',['RRT indications','dialysis emergencies','AEIOU','AKI','nephrology']);
add('neph-aki','What is acute interstitial nephritis (AIN) and what drugs cause it?','AIN: immune-mediated tubulointerstitial inflammation; most common drug causes: NSAIDs, PPIs (most common), penicillins, sulfonamides, allopurinol, rifampin, checkpoint inhibitors','Classic triad of AIN: fever + rash + eosinophilia (present in only 10% of drug-induced AIN). Urine eosinophils unreliable. Renal biopsy is gold standard. Treatment: stop offending drug; corticosteroids if no improvement in 5-7 days.',4,'apply',['AIN','acute interstitial nephritis','drug-induced','PPIs','NSAIDs','nephrology']);
add('neph-aki','A 55-year-old has AKI, thrombocytopenia, microangiopathic hemolytic anemia (MAHA), and neurological symptoms. What is the diagnosis?','Thrombotic thrombocytopenic purpura (TTP) — pentad: MAHA + thrombocytopenia + neurological symptoms + fever + renal failure; ADAMTS13 activity <10%','TTP is a medical emergency: treat with plasma exchange (plasmapheresis) to replace ADAMTS13 and remove antibodies. HUS (hemolytic uremic syndrome) is more renal-predominant, usually from Shiga toxin-producing E. coli 0157:H7 in children.',5,'analyze',['TTP','thrombotic thrombocytopenic purpura','MAHA','ADAMTS13','plasma exchange','nephrology']);
add('neph-aki','How does rhabdomyolysis cause AKI and how is it managed?','Myoglobin causes tubular toxicity and cast formation; manage with aggressive IV saline (200-1000 mL/h) to maintain urine output >200 mL/h until myoglobin cleared','Rhabdomyolysis causes: trauma (crush injury), seizures, strenuous exercise, drugs (statins, cocaine), hyperthermia. CK >10x ULN with elevated creatinine indicates rhabdomyolysis. Target urine output high to prevent cast formation in tubules.',4,'apply',['rhabdomyolysis','myoglobin','AKI','fluid resuscitation','CK','nephrology']);
add('neph-aki','What is the urinalysis finding in different types of AKI?','Pre-renal: hyaline casts, concentrated urine; ATN: muddy brown granular casts, tubular epithelial cells; AIN: WBC casts, RBC casts, possibly eosinophiluria; RPGN: RBC casts, dysmorphic RBCs; Post-renal: may be normal or have WBCs','Urinalysis with microscopy is essential in AKI workup. RBC casts indicate glomerular origin of bleeding (GN). WBC casts indicate tubular or interstitial infection/inflammation. Muddy brown casts indicate tubular necrosis.',2,'recall',['urinalysis','AKI','urine sediment','casts','nephrology']);
add('neph-aki','What is the initial evaluation of a patient presenting with AKI?','History (medications, contrast, urinary symptoms), physical exam (volume status), urine dipstick and microscopy, urine electrolytes (FENa, FEUrea), urine:serum creatinine ratio, renal ultrasound (exclude obstruction)','Renal ultrasound should be performed in all unexplained AKI to exclude obstruction (post-renal AKI). Bilateral hydronephrosis suggests bladder outlet obstruction. Post-renal AKI is reversible with prompt decompression.',2,'recall',['AKI evaluation','urinalysis','renal ultrasound','FENa','nephrology']);
add('neph-aki','A 60-year-old man has complete anuria for 24 hours. What is the most likely diagnosis and immediate management?','Bladder outlet obstruction (BPH, prostate cancer, urethral stricture) causing post-renal AKI — insert Foley catheter immediately','Complete anuria strongly suggests urinary obstruction. Post-renal AKI accounts for 5-10% of AKI cases. Renal ultrasound confirms hydronephrosis. Prompt decompression is essential as prolonged obstruction causes irreversible tubular damage. Post-obstructive diuresis can cause life-threatening electrolyte disorders.',4,'apply',['post-renal AKI','obstruction','BPH','Foley catheter','nephrology']);
add('neph-aki','What are the main differences between AKI and CKD on investigation?','AKI: acute onset, often reversible, normal or near-normal kidney size on U/S, no prior creatinine elevation; CKD: gradual onset, bilateral small echogenic kidneys, prior elevated creatinine','Distinguishing AKI from CKD affects treatment decisions. Small kidneys on ultrasound indicate longstanding CKD with fibrosis. Normal or enlarged kidneys in CKD suggest: diabetic nephropathy, amyloidosis, polycystic kidney disease, HIV nephropathy.',3,'apply',['AKI vs CKD','kidney size','ultrasound','creatinine','nephrology']);
add('neph-aki','What is the approach to AKI in a patient with suspected sepsis?','Fluid resuscitation with 30 mL/kg crystalloid bolus for sepsis-induced AKI, vasopressors (norepinephrine) for MAP <65, remove nephrotoxic drugs, avoid aminoglycosides, treat infection source','Sepsis-associated AKI is the most common cause of AKI in ICU. Surviving Sepsis Campaign and KDIGO guidelines recommend avoiding hyperchloremic solutions (excess NS); balanced crystalloids (LR) preferred to reduce AKI risk. Aggressive fluid therapy beyond initial resuscitation may worsen outcomes.',4,'apply',['sepsis-associated AKI','fluid resuscitation','vasopressors','nephrology']);

// NEPHROLOGY - neph-ckd (15)
add('neph-ckd','How is CKD defined and staged per KDIGO guidelines?','CKD: kidney damage or eGFR <60 mL/min/1.73m2 for ≥3 months; Stages: G1 (≥90), G2 (60-89), G3a (45-59), G3b (30-44), G4 (15-29), G5 (<15); also staged by albuminuria (A1/A2/A3)','KDIGO 2012 CKD guidelines define CKD by chronicity (≥3 months) to distinguish from AKI. Prognosis determined by combined GFR stage + albuminuria category. High-risk CKD: G3b-G5 or high albuminuria (A3 = ACR ≥30 mg/mmol).',2,'recall',['CKD staging','KDIGO','eGFR','albuminuria','nephrology']);
add('neph-ckd','What are the two most common causes of CKD in Canada?','Diabetes mellitus (30-40%) and hypertension (25-30%) — together account for most CKD cases requiring dialysis','Diabetic nephropathy typically presents with microalbuminuria progressing to macroalbuminuria then declining GFR. CKD Canada guidelines recommend RAAS blockade (ACEi/ARB) for all CKD patients with albuminuria regardless of BP.',2,'recall',['CKD etiology','diabetes','hypertension','nephrology']);
add('neph-ckd','What pharmacological interventions slow CKD progression?','ACEi/ARB (reduce proteinuria and intraglomerular pressure), SGLT2 inhibitors (canagliflozin/dapagliflozin reduce CKD progression), strict BP control, blood glucose control in diabetes, avoid nephrotoxins','CREDENCE and DAPA-CKD trials showed SGLT2 inhibitors reduce CKD progression and cardiovascular events in CKD patients regardless of diabetes status. CKD Canada 2022 guidelines recommend SGLT2 inhibitors for CKD G2-4 with ACR ≥20 mg/mmol.',3,'recall',['CKD progression','SGLT2 inhibitors','ACE inhibitor','CREDENCE','nephrology']);
add('neph-ckd','A 58-year-old diabetic with CKD has Hgb 95 g/L, MCV normal, ferritin 180 ng/mL, transferrin saturation 22%. Diagnosis and treatment?','Anemia of CKD (normocytic normochromic anemia from reduced erythropoietin); treat with erythropoiesis-stimulating agent (ESA) + iron to maintain Hgb 100-115 g/L — ensure iron replete first','CKD Canada guidelines recommend iron supplementation to achieve ferritin >200 ng/mL and TSAT >20% before starting ESA. ESA (darbepoetin, epoetin alfa) target Hgb 100-115 g/L (not higher — increased stroke/thrombosis risk). Oral vs. IV iron based on severity.',4,'apply',['anemia of CKD','ESA','erythropoietin','iron supplementation','nephrology']);
add('neph-ckd','What is the cause and management of hyperphosphatemia in CKD?','Reduced phosphate excretion in CKD → secondary hyperparathyroidism → renal osteodystrophy; treat with dietary phosphate restriction, phosphate binders (calcium carbonate, sevelamer, lanthanum)','CKD-MBD (mineral bone disease): hyperphosphatemia + hypocalcemia → elevated PTH → bone resorption. Sevelamer and lanthanum preferred over calcium-based binders to avoid calcium loading. Activated vitamin D (calcitriol) suppresses PTH.',3,'apply',['hyperphosphatemia','CKD-MBD','phosphate binders','sevelamer','secondary hyperparathyroidism','nephrology']);
add('neph-ckd','What BP target and agents are recommended for CKD patients with hypertension?','Target <130/80 mmHg; ACEi or ARB first-line for CKD with proteinuria (A2/A3) — provide nephroprotection beyond BP lowering','RAAS blockade reduces intraglomerular pressure and proteinuria. Monitor creatinine and potassium at 1-2 weeks after initiation. Up to 30% creatinine rise acceptable if stable. Combination ACEi + ARB increases AKI and hyperkalemia risk — avoid.',2,'recall',['CKD hypertension','ACE inhibitor','ARB','blood pressure target','nephrology']);
add('neph-ckd','What metabolic acidosis occurs in CKD and when should it be treated?','Type 4 RTA (hyperkalemic distal RTA) in early CKD; later, reduced NH4+ excretion; treat metabolic acidosis when serum bicarbonate <22 mmol/L with sodium bicarbonate supplements','KDIGO guidelines recommend treating metabolic acidosis in CKD (target bicarbonate ≥22 mmol/L) to slow CKD progression, prevent muscle catabolism, and prevent bone buffering. Sodium bicarbonate 0.5-1 mmol/kg/day titrated to bicarbonate >22.',3,'apply',['metabolic acidosis','CKD','bicarbonate supplementation','renal tubular acidosis','nephrology']);
add('neph-ckd','When should patients with CKD be referred to nephrology?','eGFR <30 (G4-G5), rapid eGFR decline (>5 mL/min/year), ACR >300 mg/mmol, resistant hypertension, unexplained AKI, hereditary kidney disease, suspected GN','CKD Canada guidelines recommend nephrology referral to prepare for renal replacement therapy, manage CKD-MBD, anemia, and cardiovascular risk. Early referral (eGFR 30-60) improves outcomes and reduces late referral (<3 months before dialysis).',2,'recall',['CKD referral','nephrology','eGFR','KDIGO','nephrology']);
add('neph-ckd','What are the renal replacement therapy options for end-stage kidney disease?','Hemodialysis (in-centre or home), peritoneal dialysis (CAPD or APD), or kidney transplantation — preferred in order of outcome benefit: transplant > PD or home HD > in-centre HD','CKD Canada recommends kidney transplant as the optimal RRT. Living donor transplant preferred over deceased donor. Peritoneal dialysis is equivalent to hemodialysis in appropriate patients and may be preferred for residual renal function preservation.',3,'recall',['RRT','dialysis','transplant','ESKD','hemodialysis','peritoneal dialysis','nephrology']);
add('neph-ckd','What dietary recommendations are made for CKD patients?','Protein restriction 0.6-0.8 g/kg/day (stage 3-5 not on dialysis), sodium <2.3 g/day, phosphate restriction, potassium restriction (if hyperkalemic), adequate caloric intake','CKD Canada dietary guidelines recommend low-protein diet to reduce uremic solute accumulation and slow CKD progression. Dialysis patients need higher protein (1.0-1.2 g/kg/day) to replace dialysis-related losses.',3,'recall',['CKD diet','protein restriction','low sodium','nephrology']);
add('neph-ckd','A 65-year-old with CKD G4 has PTH 450 pg/mL and calcium 2.55 mmol/L. Management?','Secondary hyperparathyroidism in CKD; treat with vitamin D receptor activator (calcitriol or paricalcitol) and phosphate binder — cinacalcet if PTH remains elevated despite these measures','PTH targets in CKD-MBD: CKD G3-G5 not on dialysis: maintain PTH in 2-9x upper limit of normal. Calcitriol suppresses PTH synthesis. Cinacalcet (calcimimetic) reduces PTH by sensitizing calcium-sensing receptor. Parathyroidectomy for severe refractory hyperparathyroidism.',4,'apply',['secondary hyperparathyroidism','PTH','calcitriol','cinacalcet','CKD-MBD','nephrology']);
add('neph-ckd','What cardiovascular risk does CKD impose and how should it be managed?','CKD is an independent cardiovascular risk factor; high-intensity statin recommended for all CKD patients (SHARP trial), blood pressure control, lifestyle modification, aspirin for secondary prevention','CKD patients have 10-20x higher cardiovascular mortality than age-matched general population. SHARP trial showed rosuvastatin/ezetimibe reduces major atherosclerotic events in CKD. Statin reduces LDL but survival benefit less clear once dialysis dependent.',3,'apply',['CKD cardiovascular risk','statin','SHARP trial','dyslipidemia','nephrology']);
add('neph-ckd','What is the approach to managing potassium in CKD patients?','Dietary potassium restriction (avoid high-K+ foods: bananas, citrus, potatoes), adjust medications (reduce/hold ACEi/ARB if K+ >5.5), consider patiromer or sodium zirconium cyclosilicate','Hyperkalemia is common in CKD, especially with RAAS blockade. Novel potassium binders allow continuation of life-saving GDMT (ACEi/ARB, MRA, SGLT2i). Emergency hyperkalemia: calcium gluconate, insulin + dextrose, sodium bicarbonate, kayexalate, dialysis.',3,'apply',['hyperkalemia','CKD','potassium binders','patiromer','RAAS','nephrology']);
add('neph-ckd','What is diabetic nephropathy and how does it progress?','Diabetic nephropathy progression: hyperfiltration → microalbuminuria (ACR 3-30 mg/mmol) → macroalbuminuria (ACR >30 mg/mmol) → declining GFR → ESKD','Tight glycemic control (HbA1c <7%) and RAAS blockade slow progression. SGLT2 inhibitors further reduce proteinuria and CKD progression independent of glucose control. Annual ACR and eGFR monitoring in all diabetics per CDA guidelines.',3,'recall',['diabetic nephropathy','microalbuminuria','ACR','SGLT2','nephrology']);
add('neph-ckd','When is vascular access planning initiated for hemodialysis in CKD?','Nephrology referral at eGFR <30; arteriovenous fistula (AVF) creation when eGFR <15-20 or within 6 months of anticipated dialysis start — AVF is preferred over graft over tunneled catheter','AVF has lowest infection and thrombosis rates and best long-term patency. CKD Canada recommends protecting non-dominant forearm veins (avoid IV lines and blood draws in that arm) in CKD patients who may need hemodialysis.',3,'recall',['hemodialysis access','AVF','arteriovenous fistula','CKD preparation','nephrology']);

// NEPHROLOGY - neph-electrolytes (15)
add('neph-electrolytes','A 70-year-old on HCTZ has Na+ 122 mEq/L, clinically euvolemic. Urine Na+ 40 mEq/L, urine osmolality 520 mOsm/kg. Diagnosis and management?','SIADH (syndrome of inappropriate ADH secretion); restrict water (500-1000 mL/day), correct Na+ slowly (max 8-10 mEq/L per 24h to prevent osmotic demyelination)','SIADH diagnosis: hyponatremia, hypo-osmolality, urine osmolality >100 mOsm/kg (concentrated urine despite hyponatremia), urine Na+ >20 mEq/L, euvolemia. Causes: CNS, pulmonary, malignancy, drugs (HCTZ, SSRIs). Vaptans (tolvaptan) for refractory cases.',4,'analyze',['SIADH','hyponatremia','water restriction','vaptans','nephrology']);
add('neph-electrolytes','What is the danger of correcting hyponatremia too rapidly and what is the safe correction rate?','Osmotic demyelination syndrome (ODS/central pontine myelinolysis): correction >10 mEq/L/24h or >18 mEq/L/48h in chronic hyponatremia causes permanent neurological damage','Chronic hyponatremia (>48h) is most dangerous to correct rapidly because brain cells adapt by losing osmolytes. ODS presents with locked-in syndrome, dysarthria, quadriplegia days after correction. Target: 4-8 mEq/L in first 24h for chronic hyponatremia. Symptomatic hyponatremia: 1-2 mEq/L/hour for 1-2 hours with hypertonic saline then slow down.',5,'analyze',['hyponatremia correction','osmotic demyelination','ODS','hypertonic saline','nephrology']);
add('neph-electrolytes','Classify hyponatremia by volume status with urine findings.','Hypovolemic (urine Na+ <20: extrarenal loss — GI, skin; urine Na+ >20: renal loss — diuretics, cerebral salt wasting); Euvolemic (SIADH, hypothyroidism, adrenal insufficiency); Hypervolemic (urine Na+ <20: cirrhosis, HF, nephrotic; urine Na+ >20: CKD, AKI)','Volume status assessment is the first step in hyponatremia evaluation. Clinical exam + urine Na+/osmolality guide etiology. Pseudohyponatremia: high lipids or protein. Hyperosmolar hyponatremia: hyperglycemia, mannitol.',3,'analyze',['hyponatremia classification','volume status','urine sodium','SIADH','nephrology']);
add('neph-electrolytes','A patient develops confusion, muscle weakness, and ECG changes (peaked T waves, wide QRS) with K+ 6.8 mEq/L. Immediate treatment?','IV calcium gluconate (1-2 g) immediately to stabilize cardiac membrane, then insulin 10 units IV + dextrose 50g, sodium bicarbonate if acidotic, then definitive removal (kayexalate, patiromer, or dialysis)','Calcium gluconate stabilizes cardiac membrane within minutes but does not lower K+. Insulin + dextrose shifts K+ into cells (K+ drops 0.5-1.5 mEq/L within 30 min). Beta-agonists (albuterol) also shift K+. Definitive removal requires 1-2 hours (kayexalate, patiromer) or dialysis.',4,'apply',['hyperkalemia treatment','calcium gluconate','insulin','kayexalate','nephrology']);
add('neph-electrolytes','What are the ECG findings and clinical features of hypokalemia?','K+ <3.5: muscle weakness, fatigue, constipation; ECG: U waves, T wave flattening, QT prolongation, ventricular arrhythmias (risk of TdP); severe (<2.5): paralysis, rhabdomyolysis','Hypokalemia causes: GI losses (vomiting, diarrhea), diuretics, hyperaldosteronism, renal tubular acidosis, hypomagnesemia. Treat underlying cause. Replace K+ cautiously: maximum IV rate 10-20 mEq/h through peripheral line. Correct Mg2+ simultaneously.',3,'apply',['hypokalemia','U waves','potassium replacement','ECG changes','nephrology']);
add('neph-electrolytes','What is the approach to hypercalcemia and what are the most common causes?','Causes by frequency: hyperparathyroidism (PTH-mediated, ambulatory) and malignancy (PTHrP or bone metastases, inpatient); others: sarcoidosis, vitamin D toxicity, milk-alkali syndrome','Symptoms (symptoms of hypercalcemia): bones (fractures), moans (constipation, peptic ulcer), groans (muscle weakness, polyuria/polydipsia), stones (nephrolithiasis), psychic overtones (depression, confusion). Severe hypercalcemia (>3.5 mmol/L or symptomatic): IV NS, bisphosphonates (zoledronic acid), dialysis.',3,'apply',['hypercalcemia','hyperparathyroidism','malignancy','PTH','bones moans groans stones','nephrology']);
add('neph-electrolytes','How is hypernatremia classified and managed?','Hypernatremia = Na+ >145 mEq/L; always hyperosomolar; causes: water deficit (diabetes insipidus, fever, diarrhea) or sodium gain (hypertonic saline); correct slowly (max 10 mEq/L/24h) with free water (D5W PO/IV or NG water)','Correction rate: max 10 mEq/L per 24h to prevent cerebral edema. Central DI: DDAVP (desmopressin) treatment. Nephrogenic DI: treat cause, thiazide diuretics reduce free water excretion paradoxically. Water deficit = 0.6 × weight × [(Na/140) - 1].',4,'apply',['hypernatremia','diabetes insipidus','free water deficit','correction rate','nephrology']);
add('neph-electrolytes','A patient with chronic hyponatremia is given IV hypertonic saline and overcorrects to Na+ 136 mEq/L from 118 mEq/L in 18 hours. What should be done?','Re-lower sodium with DDAVP + D5W infusion (3% saline relowering protocol) to prevent osmotic demyelination syndrome','Overcorrection is a medical emergency. DDAVP (desmopressin) 2 mcg IV plus D5W 6 mL/kg/h can re-lower sodium by 1-2 mEq/L/hour. Prevention is key: use DDAVP-clamp method in high-risk patients (Na+ <120, malnutrition, alcohol use, hypokalemia).',5,'analyze',['hyponatremia overcorrection','DDAVP clamp','osmotic demyelination','relowering protocol','nephrology']);
add('neph-electrolytes','What causes metabolic alkalosis and how is it classified?','Saline-responsive (urine Cl- <25 mEq/L): vomiting, nasogastric suction, diuretic use — treat with IV normal saline; Saline-resistant (urine Cl- >25 mEq/L): hyperaldosteronism, Cushing syndrome, severe hypokalemia','Metabolic alkalosis: HCO3- >26 mEq/L, pH >7.40. Maintenance: hypovolemia stimulates aldosterone (retains HCO3-) and hypokalemia drives H+ into cells. Saline-responsive metabolic alkalosis is most common (GI losses, diuretics).',3,'analyze',['metabolic alkalosis','saline-responsive','chloride','vomiting','nephrology']);
add('neph-electrolytes','What is the anion gap and when is it elevated?','AG = Na - (Cl + HCO3), normal 8-12 mEq/L; elevated in: MUDPILES: Methanol, Uremia, DKA, Propylene glycol, Isoniazid/Iron, Lactic acidosis, Ethylene glycol, Salicylates','Elevated AG metabolic acidosis requires urgent identification and treatment of cause. Delta ratio: if (elevated AG - 12) / (24 - HCO3) >2, suggests concurrent metabolic alkalosis; <1 suggests concurrent non-AG metabolic acidosis.',2,'recall',['anion gap','metabolic acidosis','MUDPILES','AG metabolic acidosis','nephrology']);
add('neph-electrolytes','What is the management of diabetic ketoacidosis (DKA) with electrolyte focus?','IV insulin infusion + isotonic saline, potassium replacement (IV K+ when K+ <5.5 and urine output adequate), sodium bicarbonate only for pH <6.9, monitor glucose hourly and electrolytes q2-4h','DKA causes total body K+ depletion despite initial serum K+ appearing normal/high (acidosis shifts K+ extracellularly). Potassium must be given before insulin if K+ <3.5 mEq/L. Phosphate replacement for severe hypophosphatemia (<0.32 mmol/L).',4,'apply',['DKA','potassium replacement','insulin infusion','electrolytes in DKA','nephrology']);
add('neph-electrolytes','A 45-year-old has serum phosphate 0.4 mmol/L, muscle weakness, and respiratory failure. What is the management?','Severe hypophosphatemia (<0.32 mmol/L): IV phosphate replacement (sodium phosphate or potassium phosphate); mild-moderate: oral phosphate supplements','Causes of hypophosphatemia: refeeding syndrome, DKA treatment, alcoholism, hyperparathyroidism, antacids. Severe hypophosphatemia causes: hemolytic anemia, rhabdomyolysis, cardiac dysfunction, respiratory muscle weakness. IV replacement rate: 0.16-0.32 mmol/kg over 4-6h.',4,'apply',['hypophosphatemia','refeeding syndrome','IV phosphate','respiratory failure','nephrology']);
add('neph-electrolytes','What are the causes and treatment of hypomagnesemia?','Causes: poor intake (alcoholism), GI losses (diarrhea, malabsorption), renal losses (diuretics, cisplatin, PPIs), diabetes; treat with IV magnesium sulfate for symptomatic or severe (<0.4 mmol/L)','Hypomagnesemia is common in hospitalized patients. It causes: hypokalemia (resistant to K+ replacement unless Mg2+ corrected), hypocalcemia, cardiac arrhythmias (TdP). PPIs can cause chronic magnesium wasting. IV MgSO4 2-4g for acute symptomatic hypomagnesemia.',3,'apply',['hypomagnesemia','magnesium replacement','hypokalemia','cardiac arrhythmia','nephrology']);
add('neph-electrolytes','What is refeeding syndrome and how is it prevented?','Hypophosphatemia, hypokalemia, hypomagnesemia occurring 1-4 days after refeeding malnourished patients; prevent by correcting electrolytes before feeding, start feeds slowly, supplement thiamine','Refeeding syndrome occurs due to rapid intracellular shift of phosphate, K+, and Mg2+ during anabolism after starvation. Risk groups: malnutrition, alcoholism, anorexia nervosa, prolonged fasting, post-surgery. Thiamine deficiency causes Wernicke encephalopathy if carbohydrates given without thiamine.',4,'analyze',['refeeding syndrome','hypophosphatemia','thiamine','malnutrition','nephrology']);
add('neph-electrolytes','How is diabetes insipidus (DI) diagnosed and differentiated from psychogenic polydipsia?','Water deprivation test: DI fails to concentrate urine (osmolality <300 mOsm/kg); central DI responds to DDAVP; nephrogenic DI does not respond to DDAVP; psychogenic polydipsia: concentrated urine after restriction','Central DI: ADH deficiency from pituitary/hypothalamic damage (trauma, tumors, surgery). Nephrogenic DI: ADH resistance (lithium toxicity, hypercalcemia, hypokalemia, hereditary). Serum ADH/copeptin levels can aid diagnosis before water deprivation.',4,'analyze',['diabetes insipidus','water deprivation test','DDAVP','central vs nephrogenic','nephrology']);

// NEPHROLOGY - neph-glom (7)
add('neph-glom','A 5-year-old boy develops periorbital edema, massive proteinuria (>3.5 g/day), hypoalbuminemia, and hypercholesterolemia after an URI. What is the diagnosis and treatment?','Minimal change disease (MCD) presenting as nephrotic syndrome in a child; first-line treatment is oral prednisone (60 mg/m2/day or 2 mg/kg/day) — expect complete remission in 80-90%','MCD is the most common cause of nephrotic syndrome in children. Responds dramatically to steroids. Lipoid nephrosis is another term. Diagnosis: clinical response to steroids; biopsy only if steroid-resistant or atypical features.',3,'apply',['minimal change disease','nephrotic syndrome','children','prednisone','nephrology']);
add('neph-glom','What are the clinical features of nephrotic syndrome vs. nephritic syndrome?','Nephrotic: massive proteinuria (>3.5 g/day), hypoalbuminemia (<25 g/L), edema, hyperlipidemia, lipiduria — no hematuria; Nephritic: hematuria (RBC casts), proteinuria (less massive), hypertension, oliguria, AKI','Nephrotic causes: MCD, FSGS, membranous nephropathy, diabetic nephropathy, amyloid. Nephritic causes: IgA nephropathy, post-streptococcal GN, anti-GBM disease, ANCA vasculitis, lupus nephritis.',2,'recall',['nephrotic syndrome','nephritic syndrome','proteinuria','hematuria','nephrology']);
add('neph-glom','A 35-year-old has hypertension, microscopic hematuria, and mild proteinuria. Renal biopsy shows IgA deposits in mesangium. Diagnosis and prognosis?','IgA nephropathy (Berger disease) — most common primary GN worldwide; 20-30% progress to ESKD over 20-30 years; high-risk features: persistent hypertension, heavy proteinuria, elevated creatinine','CKD Canada/KDIGO KDIGO 2021 guidelines: ACEi/ARB for proteinuria >500 mg/day, blood pressure control. Targeted release budesonide (Nefecon) approved for high-risk IgA nephropathy. Sparsentan (dual endothelin/AT1 blocker) reduces proteinuria.',4,'analyze',['IgA nephropathy','Berger disease','hematuria','proteinuria','nephrology']);
add('neph-glom','A 60-year-old presents with hemoptysis and hematuria. ANCA (MPO-ANCA/p-ANCA) is positive. Renal biopsy shows pauci-immune crescentic GN. Diagnosis and treatment?','Microscopic polyangiitis or granulomatosis with polyangiitis (Wegener) — ANCA vasculitis; treat with pulse IV methylprednisolone + cyclophosphamide (or rituximab) induction, then azathioprine maintenance','ANCA-associated vasculitis (AAV) requires immediate immunosuppression to preserve kidney function. PR3-ANCA (c-ANCA) = GPA; MPO-ANCA (p-ANCA) = MPA or eosinophilic GPA (eGPA). Plasma exchange added for dialysis-dependent or pulmonary hemorrhage.',5,'analyze',['ANCA vasculitis','GPA','MPA','crescentic GN','cyclophosphamide','nephrology']);
add('neph-glom','A 25-year-old woman with SLE has proteinuria 4g/day, RBC casts, and low complement. Renal biopsy shows diffuse proliferative GN (Class IV lupus nephritis). Treatment?','Class III/IV lupus nephritis: mycophenolate mofetil (MMF) or cyclophosphamide induction + high-dose corticosteroids; MMF + belimumab or voclosporin as newer combination approach','ISN/RPS classification: Class III (focal) and IV (diffuse) LN require immunosuppressive induction. MMF has equivalent efficacy and better tolerability than cyclophosphamide for most patients. Maintenance: MMF + hydroxychloroquine + low-dose steroids.',4,'apply',['lupus nephritis','SLE','MMF','Class IV LN','nephrology']);
add('neph-glom','A 55-year-old man has nephrotic syndrome with proteinuria 8g/day and subepitheial deposits on electron microscopy. Serology negative. Diagnosis and treatment?','Membranous nephropathy; 30% spontaneous remission; treat high-risk patients (persistent heavy proteinuria, declining GFR) with rituximab (preferred) or cyclophosphamide-based regimen','Membranous nephropathy: most common cause of nephrotic syndrome in adults >50. 80% have PLA2R antibodies. Rituximab has replaced older regimens. Check for secondary causes (malignancy, infections, drugs, lupus) before assuming primary.',4,'analyze',['membranous nephropathy','nephrotic syndrome','PLA2R','rituximab','nephrology']);
add('neph-glom','What is post-streptococcal glomerulonephritis (PSGN) and when does it occur?','PSGN: immune complex GN occurring 1-3 weeks after group A strep pharyngitis or 3-6 weeks after strep skin infection; presents with hematuria, edema, hypertension, low C3','PSGN is most common in children. Diagnosis: low serum C3, elevated ASO titer, throat/skin culture. Renal biopsy not usually required. Treatment: supportive (diuretics, antihypertensives); antibiotics to eradicate strep but do not prevent GN. Prognosis excellent in children.',3,'apply',['post-streptococcal GN','PSGN','low complement','hematuria','strep infection','nephrology']);

// ENDOCRINOLOGY - endo-dm (20)
add('endo-dm','A 52-year-old obese patient with fasting glucose 7.8 mmol/L and HbA1c 7.4% (57 mmol/mol) on two separate occasions. Diagnosis and initial management?','Type 2 diabetes mellitus; first-line: lifestyle modification (diet, exercise, weight loss) + metformin unless contraindicated','CDA/Diabetes Canada 2018 guidelines diagnose T2DM with: fasting glucose ≥7.0 mmol/L, random glucose ≥11.1 mmol/L, 2h OGTT ≥11.1 mmol/L, or HbA1c ≥6.5% — confirmed with a second test unless symptomatic. Metformin reduces HbA1c by 1-1.5%.',3,'apply',['type 2 diabetes','diagnosis','metformin','HbA1c','endocrinology']);
add('endo-dm','What are the HbA1c targets in diabetes management per Diabetes Canada guidelines?','Most adults: HbA1c ≤7.0%; if high hypoglycemia risk or frail elderly: ≤8.0-8.5%; if low hypoglycemia risk with shorter duration and multiple risk factors: ≤6.5%','Diabetes Canada guidelines individualize HbA1c targets. Tighter control (≤7%) reduces microvascular complications (retinopathy, nephropathy, neuropathy). Looser control in elderly or hypoglycemia-prone patients. UKPDS and DCCT support intensive control.',2,'recall',['HbA1c target','glycemic control','Diabetes Canada','type 2 diabetes','endocrinology']);
add('endo-dm','Which class of antidiabetic agents reduces cardiovascular mortality in T2DM patients with established CVD?','SGLT2 inhibitors (empagliflozin, canagliflozin, dapagliflozin) and GLP-1 receptor agonists (liraglutide, semaglutide) have cardiovascular outcome benefit — SGLT2i preferred with HF or CKD; GLP-1 RA preferred with atherosclerotic CVD','Diabetes Canada guidelines recommend SGLT2 inhibitor or GLP-1 RA as second-line after metformin for patients with established CVD, HF, or CKD — regardless of glycemic control. EMPA-REG, CANVAS, LEADER, SUSTAIN-6 trials established these benefits.',3,'apply',['SGLT2 inhibitors','GLP-1 receptor agonist','cardiovascular benefit','T2DM','empagliflozin','endocrinology']);
add('endo-dm','A 25-year-old with type 1 diabetes has nausea, abdominal pain, blood glucose 28 mmol/L, blood gases pH 7.18, bicarbonate 10 mmol/L, ketones 4+. Diagnosis and immediate management?','Diabetic ketoacidosis (DKA); immediate IV regular insulin infusion (0.1 units/kg/h), IV isotonic saline, potassium replacement (before insulin if K+ <3.5), identify and treat precipitant','DKA diagnostic criteria: glucose >14 mmol/L (may be normal in euglycemic DKA), ketonemia/ketonuria, pH <7.30, bicarbonate <15 mmol/L. Fluid deficit is 3-5L. Insulin drip continued until anion gap closed. Transition to subcutaneous insulin with overlap.',5,'analyze',['DKA','diabetic ketoacidosis','insulin','potassium','endocrinology']);
add('endo-dm','What is hyperosmolar hyperglycemic state (HHS) and how does it differ from DKA?','HHS: glucose >33 mmol/L, osmolality >320 mOsm/kg, minimal ketones, no significant acidosis (pH >7.30) — occurs in T2DM; DKA: significant ketosis and acidosis, occurs in T1DM (and T2DM)','HHS has higher mortality than DKA (5-20% vs <1%). Fluid deficit larger (8-10L). Correct volume deficit first, then reduce glucose slowly (5 mmol/L/h). Insulin infusion at lower rates. Heparin prophylaxis for DVT risk.',5,'analyze',['HHS','hyperosmolar hyperglycemic state','DKA','hyperglycemia','endocrinology']);
add('endo-dm','A T1DM patient has recurrent hypoglycemic episodes. What is hypoglycemia unawareness and how is it managed?','Hypoglycemia unawareness: loss of autonomic warning symptoms due to recurrent hypoglycemia; manage by strict hypoglycemia avoidance (higher glucose targets for 2-3 weeks to restore awareness) and CGM','Diabetes Canada guidelines recommend continuous glucose monitoring (CGM) and insulin pump therapy (CSII) for T1DM patients with hypoglycemia unawareness to reduce severe hypoglycemia. Relaxing glycemic targets temporarily restores counter-regulatory response.',4,'analyze',['hypoglycemia unawareness','T1DM','CGM','insulin pump','endocrinology']);
add('endo-dm','What screening does Diabetes Canada recommend for complications of diabetes?','Annual: HbA1c q3months until stable then q6months, annual urine ACR and eGFR, annual dilated eye exam (ophthalmology), foot exam at every visit, lipid profile and BP annually','Diabetes Canada guidelines recommend systematic monitoring for microvascular (retinopathy, nephropathy, neuropathy) and macrovascular complications. Eye exam within 5 years of T1DM onset; at diagnosis for T2DM. Monofilament testing for peripheral neuropathy.',2,'recall',['diabetes complications screening','annual monitoring','ACR','retinopathy','Diabetes Canada','endocrinology']);
add('endo-dm','What medications should be avoided or used with caution in T2DM with CKD?','Metformin: hold if eGFR <30, reduce dose if eGFR 30-45; SGLT2 inhibitors: less effective eGFR <45 but cardioprotective; avoid certain sulfonylureas (glibenclamide — renal clearance); adjust insulin doses','CDA/Diabetes Canada guidelines provide drug-specific guidance by eGFR level. SGLT2 inhibitors (specifically canagliflozin and dapagliflozin) have nephroprotective effects at eGFR 25-60. Metformin lactic acidosis risk in renal failure.',3,'apply',['diabetes and CKD','metformin','SGLT2i','renal dosing','endocrinology']);
add('endo-dm','What is the Somogyi effect vs. the dawn phenomenon in diabetes?','Somogyi effect (disputed): rebound hyperglycemia after nocturnal hypoglycemia; Dawn phenomenon: physiologic early morning hyperglycemia from GH and cortisol surge — both cause high morning glucose','Dawn phenomenon is well-established; Somogyi effect is controversial. Differentiation: check 3 AM glucose — low (Somogyi/nocturnal hypoglycemia) vs. normal (dawn phenomenon). Treatment: dawn phenomenon → increase evening basal insulin or use CSII.',3,'apply',['Somogyi effect','dawn phenomenon','morning hyperglycemia','T1DM','endocrinology']);
add('endo-dm','What is the mechanism of metformin and its main contraindications?','Metformin decreases hepatic gluconeogenesis (reduces hepatic glucose production); contraindications: eGFR <30, active liver disease, heart failure requiring hospitalization, metabolic acidosis','Metformin does not cause hypoglycemia when used alone. It reduces HbA1c 1-1.5%, is weight-neutral, and has CV benefits (UKPDS). Hold metformin perioperatively and 48h after IV contrast if AKI risk. Vitamin B12 deficiency with long-term use.',2,'recall',['metformin','mechanism','contraindications','T2DM','endocrinology']);
add('endo-dm','What are the benefits and adverse effects of SGLT2 inhibitors in T2DM?','Benefits: HbA1c reduction 0.5-1%, weight loss, BP reduction, SGLT2i CV and renal benefits; side effects: genital mycotic infections, UTI, DKA (euglycemic DKA — especially with fasting/surgery), volume depletion, lower limb amputations (canagliflozin)','Diabetes Canada guidelines recommend SGLT2 inhibitors for patients with T2DM and CVD, HF, or CKD. Hold 3-4 days before surgery to prevent euglycemic DKA. Genital infections more common in women.',3,'apply',['SGLT2 inhibitors','side effects','genital mycotic','euglycemic DKA','endocrinology']);
add('endo-dm','A T2DM patient on metformin + glyburide has a blood glucose of 2.1 mmol/L after skipping lunch. What is the immediate treatment and long-term adjustment?','Hypoglycemia: immediate treatment with 15g fast-acting carbohydrate (glucose tablets, juice); recheck in 15 min; long-term: switch from glyburide to lower-risk agent (SGLT2i, DPP4i) or reduce glyburide dose','Sulfonylureas (especially glyburide) cause prolonged hypoglycemia due to long duration of action. Elderly patients and those with irregular meals or CKD are at highest risk. DPP4 inhibitors, SGLT2i, and GLP-1 RA have lower hypoglycemia risk.',4,'apply',['hypoglycemia','sulfonylurea','glyburide','15g rule','endocrinology']);
add('endo-dm','What are the diagnostic criteria for pre-diabetes?','Impaired fasting glucose: fasting glucose 6.1-6.9 mmol/L; Impaired glucose tolerance: 2h OGTT 7.8-11.0 mmol/L; HbA1c 6.0-6.4% (42-46 mmol/mol)','Diabetes Canada recommends lifestyle intervention (weight loss ≥5-7%, 150 min/week moderate exercise) for pre-diabetes — reduces progression to T2DM by 58% (DPP trial). Metformin is an option for high-risk pre-diabetes patients.',2,'recall',['pre-diabetes','IFG','IGT','HbA1c','endocrinology']);
add('endo-dm','What is the recommended approach to diabetes management in pregnancy?','Type 1/2 DM in pregnancy: insulin is the only recommended agent (oral agents except metformin are not approved); tight glycemic targets (fasting <5.3, 1h post-meal <7.8, 2h <6.7 mmol/L)','Gestational diabetes mellitus (GDM) is diagnosed by 75g OGTT at 24-28 weeks. Initial management: medical nutrition therapy; add insulin if targets not met within 2 weeks. Metformin acceptable as second-line in GDM per Diabetes Canada/SOGC.',4,'apply',['diabetes in pregnancy','GDM','gestational diabetes','insulin','SOGC','endocrinology']);
add('endo-dm','What is the target blood pressure in patients with diabetes and hypertension?','BP target <130/80 mmHg in diabetes per Diabetes Canada and Hypertension Canada — ACEi or ARB preferred agents for nephroprotection','Tight BP control in diabetes reduces stroke, MI, and nephropathy progression. ACCORD-BP trial: SBP target <120 vs. <140 — no CV mortality reduction but lower stroke rates with tighter control. CDA recommends individualized targets.',2,'recall',['diabetes hypertension','BP target','ACE inhibitor','nephroprotection','endocrinology']);
add('endo-dm','A patient with T2DM on metformin has HbA1c 8.4% despite maximum metformin dose. What is the preferred second-line agent if they have established CVD?','SGLT2 inhibitor (empagliflozin, canagliflozin) or GLP-1 receptor agonist (liraglutide, semaglutide) — both have proven cardiovascular mortality reduction in established CVD','Diabetes Canada 2022 guidelines prioritize SGLT2i and GLP-1 RA as second-line agents for patients with established CVD, HF, or CKD. The choice between them is guided by comorbidities: SGLT2i preferred with HF/CKD, GLP-1 RA preferred with high ASCVD risk.',3,'apply',['T2DM second-line','SGLT2i','GLP-1 RA','established CVD','empagliflozin','endocrinology']);
add('endo-dm','What are the microvascular complications of diabetes and how are they prevented?','Retinopathy (leading cause of blindness in adults), nephropathy (leading cause of ESKD), neuropathy (peripheral: burning/numbness, autonomic: gastroparesis, orthostatic hypotension); prevented by tight glycemic control and BP management','DCCT (T1DM) and UKPDS (T2DM) trials established that HbA1c reduction significantly reduces microvascular complications. Every 1% HbA1c reduction reduces retinopathy risk by 35-40%, nephropathy by 25-35%. ACEi/ARB nephroprotective in diabetic nephropathy.',2,'recall',['diabetic microvascular','retinopathy','nephropathy','neuropathy','endocrinology']);
add('endo-dm','What is the treatment of diabetic peripheral neuropathy pain?','First-line: duloxetine (SNRI) or pregabalin/gabapentin; second-line: tricyclic antidepressants (amitriptyline), venlafaxine; topical capsaicin or lidocaine for localized pain','Tight glycemic control is the primary prevention strategy. Pregabalin (FDA-approved for DPN), duloxetine (FDA-approved), and amitriptyline (off-label but effective) are first-line options per Diabetes Canada pain guidelines. Opioids are not recommended.',3,'recall',['diabetic neuropathy','pain management','pregabalin','duloxetine','amitriptyline','endocrinology']);
add('endo-dm','What are the screening criteria for type 2 diabetes in Canada?','Screen adults ≥40 years every 3 years with fasting glucose or HbA1c; screen at any age with risk factors: obesity (BMI ≥30), first-degree family history, high-risk ethnicity (South Asian, African, Indigenous, Hispanic), prior GDM, prediabetes, CVD, medications causing hyperglycemia','Diabetes Canada 2022 guidelines recommend risk-stratified screening. CANRISK questionnaire can identify high-risk individuals. High-risk ethnic groups have higher T2DM prevalence and lower BMI thresholds.',2,'recall',['T2DM screening','Diabetes Canada','CANRISK','high-risk ethnicity','endocrinology']);
add('endo-dm','What is the sick day management protocol for T1DM patients?','Never stop insulin during illness; increase blood glucose monitoring (q2-4h), check ketones, maintain hydration, adjust insulin dose; insulin requirements typically INCREASE during illness','Illness, stress, and infection cause insulin resistance requiring more insulin. DKA commonly triggered by missed insulin doses or insufficient sick-day management. Diabetes Canada sick day rules: check glucose and ketones q4h, maintain at least basal insulin, seek care if vomiting prevents oral intake or ketones are rising.',3,'apply',['sick day management','T1DM','insulin','illness','DKA prevention','endocrinology']);

